import './App.css';
import { useState, useEffect } from 'react';
import Chart from './components/Chart';
import Header from './components/Header'
import Table from './components/Table'
import Summary from './components/Summary'
import MortgageValues from './components/MortgageValues'
import { BrowserRouter, Route, Switch } from 'react-router-dom'

const App = () => {
  const [data, setData] = useState([])
  const [amount, setAmount] = useState(250000);
  const [term, setTerm] = useState(300);
  const [interest, setInterest] = useState(3);
  const [date, setDate] = useState(new Date())
  const handleAmount = a=>setAmount(a)
  const handleTerm = t=>setTerm(t)
  const handleInterest = i=>setInterest(i)
  const handleDate = d=>setDate(d)
  const I = interest/100/12
  const M = amount * I * (Math.pow(1 + I, term)) / (Math.pow(1 + I, term) - 1)
  const [totalInterest, setTotalInterest] = useState(0)
  
  useEffect(()=> {
    const myData = []
    let myBalance = amount
    let myDate = new Date(date)
    let totalRate = 0
    for (let i=0; i<term; i++){
      let newDate = new Date(myDate.setMonth(myDate.getMonth()+1))
      myBalance -= (M - (myBalance*I)) 
      totalRate += (myBalance*I)
      myData.push({
        name: `${newDate.toLocaleString('en-us', {month: 'short'})} ${newDate.getFullYear()}`,
        principle: (M - (myBalance*I)).toFixed(2),
        interest: (myBalance*I).toFixed(2),
        balance: myBalance.toFixed(2)
      })
    }
    setData(myData)
    setTotalInterest(totalRate.toFixed(2))
  }, [amount, term, I, M, interest, date])

  return(
    <BrowserRouter>
    <div className='app container p-2'>
      <Header date={new Date(date).toISOString().split('T')[0]} setDate={handleDate} />
      <Chart data={data}/>
      <MortgageValues amount={amount} setAmount={handleAmount} term={term} setTerm={handleTerm} interest={interest} setInterest={handleInterest} />
      <Summary  M={M} T={term} totalInterest={totalInterest} />
    
    <Switch>
    <Route path='/schedule' render={props=>( <Table {...props} data={data} /> )} />
    </Switch>
    </div>
    </BrowserRouter>
  )
}

export default App;