import { useState, useEffect } from 'react';
import { NavLink } from 'react-router-dom';

const Summary = ({ M, T, totalInterest }) => {
   const [switchNumber, setSwitchNumber] = useState(true)
   const handleSwitchChange = () => {
      switchNumber? setSwitchNumber(false) : setSwitchNumber(true)
      }
    return(
       <div className='card-header border-top container p-1 my-2'>
          <div className='d-flex justify-content-between'>
            <div className='d-flex'>Monthly Payment: ${M.toFixed(2)}</div>
            <div className='d-flex'>Term: {`${(T/12.0).toFixed(2)} Years`}</div>
            <div className='d-flex'>Total Interest: ${totalInterest}</div>
           </div>

           <div className='custom-control custom-switch d-flex justify-content-between my-2'>
               <input
                  type='checkbox'
                  className='custom-control-input'
                  id='customSwitches'
                  checked={switchNumber}
                  onChange={handleSwitchChange}
                  readOnly
               />
               <label className='custom-control-label' htmlFor='customSwitches'>
                  Show Schedule
               </label>
               <NavLink to='/mortgage'>Home</NavLink>
               <NavLink to='/schedule'>Schedule</NavLink>
            </div>
            



        </div>
     )
   }
   
   export default Summary;